#!/usr/bin/env node
// validate-theorem-drift.mjs
// Walks TS files, extracts JSDoc citations of Lean theorem names, cross-checks
// against actual Lean declarations. Reports citations that no longer resolve.
//
// Usage:
//   node scripts/validate-theorem-drift.mjs         # human report
//   node scripts/validate-theorem-drift.mjs --json  # machine-readable
//
// Exit: 0 if no ERROR drift, 1 otherwise.

import { readdirSync, readFileSync, statSync } from 'node:fs';
import { join, relative } from 'node:path';

const REPO_ROOT = '.';
const TS_ROOTS = [
  { label: 'gnosis/src', path: join(REPO_ROOT, 'open-source/gnosis/src') },
  { label: 'x-ranger/src', path: join(REPO_ROOT, 'open-source/x-ranger/src') },
];
const LEAN_ROOTS = [
  { label: 'gnosis/lean', path: join(REPO_ROOT, 'open-source/gnosis/lean/Lean/ForkRaceFoldTheorems') },
  { label: 'gnosis/lean-minimal', path: join(REPO_ROOT, 'open-source/gnosis/lean-minimal/Lean/ForkRaceFoldTheorems') },
];

const IDENT_RE = /^[a-z_][a-zA-Z0-9_]*$/;
const JSON_MODE = process.argv.includes('--json');

function walk(dir, ext, out = []) {
  let entries;
  try { entries = readdirSync(dir); } catch { return out; }
  for (const name of entries) {
    const p = join(dir, name);
    let s;
    try { s = statSync(p); } catch { continue; }
    if (s.isDirectory()) {
      if (name === 'node_modules' || name === 'dist' || name === '.git') continue;
      walk(p, ext, out);
    } else if (name.endsWith(ext)) {
      out.push(p);
    }
  }
  return out;
}

// Collect Lean declarations: theorem/lemma/def at line start (ignoring docstring mentions).
function collectLeanDecls(paths) {
  const DECL_RE = /^\s*(?:private\s+|protected\s+|noncomputable\s+)?(?:theorem|lemma|def)\s+(\w+)/gm;
  const names = new Map(); // name -> [{root, file, line}]
  const counts = { theorem: 0, def: 0, lemma: 0, perRoot: {} };
  for (const root of paths) {
    const files = walk(root.path, '.lean');
    let rootCount = 0;
    for (const f of files) {
      const src = readFileSync(f, 'utf8');
      // Strip block doc comments /-! ... -/ and /-- ... -/ so mentions in docs don't match.
      const stripped = src.replace(/\/-[-!][\s\S]*?-\//g, (m) => ' '.repeat(m.length));
      DECL_RE.lastIndex = 0;
      for (const m of stripped.matchAll(DECL_RE)) {
        const name = m[1];
        const line = stripped.slice(0, m.index).split('\n').length;
        const arr = names.get(name) || [];
        arr.push({ root: root.label, file: f, line });
        names.set(name, arr);
        rootCount++;
      }
    }
    counts.perRoot[root.label] = rootCount;
  }
  return { names, counts };
}

// Extract citations from a TS file.
// Patterns considered AUTHORITATIVE Lean citations (strong signal):
//   @cite NAME / @theorem NAME
//   Mirror of `NAME` [/ `NAME` / `NAME`] (Lean)
//   `NAME` (Lean) -- backtick followed by (Lean) marker
// Generic backtick mentions of camelCase identifiers WITHOUT a Lean marker are
// not counted as citations (they are usually TS symbols, not Lean theorems).
function extractCitations(tsPath, src) {
  const citations = [];
  const push = (name, line) => {
    if (!IDENT_RE.test(name)) return;
    citations.push({ name, line });
  };

  const JSDOC_RE = /\/\*\*[\s\S]*?\*\//g;
  for (const m of src.matchAll(JSDOC_RE)) {
    const block = m[0];
    const blockStartLine = src.slice(0, m.index).split('\n').length;
    const lineAt = (idx) => blockStartLine + block.slice(0, idx).split('\n').length - 1;

    // @cite / @theorem tags.
    for (const cm of block.matchAll(/@(?:cite|theorem)\s+(\w+)/g)) {
      push(cm[1], lineAt(cm.index));
    }

    // Mirror of `A` / `B` (Lean) -- possibly chained with / , or "and".
    for (const mm of block.matchAll(/Mirror of\s+((?:`\w+`\s*(?:\/|,|and)?\s*)+)\(Lean\)/g)) {
      const line = lineAt(mm.index);
      for (const nm of mm[1].matchAll(/`(\w+)`/g)) push(nm[1], line);
    }

    // `NAME` (Lean) -- direct marker, outside the Mirror-of construct.
    for (const bm of block.matchAll(/`(\w+)`\s*\(Lean\)/g)) {
      push(bm[1], lineAt(bm.index));
    }
  }
  return citations;
}

function main() {
  const lean = collectLeanDecls(LEAN_ROOTS);
  const leanNames = lean.names;

  const tsStats = {};
  const allCitations = []; // { file, line, name }
  for (const root of TS_ROOTS) {
    const files = walk(root.path, '.ts').filter((f) => !f.endsWith('.d.ts'));
    tsStats[root.label] = files.length;
    for (const f of files) {
      const src = readFileSync(f, 'utf8');
      const cites = extractCitations(f, src);
      for (const c of cites) allCitations.push({ file: f, ...c });
    }
  }

  // Dedup citations by (file,line,name) to avoid generic-backtick double-counts with Mirror.
  const seen = new Set();
  const uniqueCitations = [];
  for (const c of allCitations) {
    const k = `${c.file}:${c.line}:${c.name}`;
    if (seen.has(k)) continue;
    seen.add(k);
    uniqueCitations.push(c);
  }

  // All citations reach here via explicit Lean markers (@cite, Mirror-of, `X`(Lean))
  // so they are all worth checking.
  const considered = uniqueCitations;
  const citedNames = new Set(considered.map((c) => c.name));
  const matched = considered.filter((c) => leanNames.has(c.name));
  const drift = considered.filter((c) => !leanNames.has(c.name));

  // Orphans: lean names not cited anywhere.
  const orphans = [];
  for (const n of leanNames.keys()) if (!citedNames.has(n)) orphans.push(n);

  const report = {
    ts: tsStats,
    lean: lean.counts.perRoot,
    leanTotalUnique: leanNames.size,
    citationsConsidered: considered.length,
    matched: matched.length,
    drift: drift.map((d) => ({
      file: relative(REPO_ROOT, d.file),
      line: d.line,
      name: d.name,
    })),
    orphansCount: orphans.length,
  };

  if (JSON_MODE) {
    process.stdout.write(JSON.stringify(report, null, 2) + '\n');
  } else {
    const tsSummary = Object.entries(tsStats).map(([k, v]) => `${v} TS files in ${k}`).join(', ');
    const leanSummary = Object.entries(lean.counts.perRoot).map(([k, v]) => `${v} decls in ${k}`).join(', ');
    console.log('Theorem citation drift report');
    console.log('=============================');
    console.log('');
    console.log(`Scanned: ${tsSummary}`);
    console.log(`Lean corpus: ${leanSummary} (${leanNames.size} unique names)`);
    console.log('');
    console.log(`Citations found: ${considered.length} (via backtick + @cite + Mirror patterns)`);
    console.log(`  matched: ${matched.length}`);
    console.log(`  drift:   ${drift.length} (ERROR)`);
    console.log('');
    if (drift.length) {
      console.log('Drift:');
      for (const d of drift) {
        console.log(`  ERROR  ${relative(REPO_ROOT, d.file)}:${d.line}  cites \`${d.name}\` -- not found in Lean corpus`);
      }
      console.log('');
    }
    console.log(`Orphan Lean theorems (not cited in TS): ${orphans.length} (info, not an error)`);
  }

  process.exit(drift.length ? 1 : 0);
}

main();
